class Solution {
public:
    int bestClosingTime(string customers) {
        int n = customers.size();
        int min_penalty = INT_MAX;
        int best_hour = 0;
        for (int i = 0; i <= n; i++) {
            int penalty = 0;
            for (int j = 0; j < n; j++) {
                if (j < i && customers[j] == 'N') penalty++;
                if (j >= i && customers[j] == 'Y') penalty++;
            }
            if (penalty < min_penalty) {
                min_penalty = penalty;
                best_hour = i;
            }
        }
        return best_hour;
    }
};

